INSERT INTO `appointment_messages` VALUES (31, 1771, 95123, 'Boa noite! Não poderei comparecer. Surgiu um imprevisto profissional.', 0, 1, '2026-03-01 23:22:53');
INSERT INTO `appointment_messages` VALUES (32, 1778, 96731, 'Bom dia! Tudo bem? Vou  ter que desmarcar o meu horário surgiu um imprevisto. Grata. Marieta A. Marques', 0, 0, '2026-03-03 08:39:25');
INSERT INTO `appointment_messages` VALUES (33, 1778, 96731, 'OAB/SC 19.147', 0, 0, '2026-03-03 08:39:38');
INSERT INTO `appointment_messages` VALUES (34, 1797, 97966, 'bom dia', 0, 0, '2026-03-05 11:58:55');
INSERT INTO `appointment_messages` VALUES (35, 1797, 97966, 'eu não vou conseguir comparecer no horário', 0, 0, '2026-03-05 11:59:10');
INSERT INTO `appointment_messages` VALUES (36, 1902, 95235, 'Boa noite , eu não moro em Florianópolis, essa conversa pode ser on line ?', 0, 0, '2026-03-17 23:45:21');
INSERT INTO `appointment_messages` VALUES (37, 1940, 107096, 'Bom dia, fiz o agendamento ontem, contudo acreditava ser de forma remota.', 0, 0, '2026-03-26 10:19:58');
INSERT INTO `appointment_messages` VALUES (38, 1980, 109995, 'Bom dia, gostaria de confirmar o horário acima para emissão de senha GOV de cliente. Obrigado.', 0, 0, '2026-03-31 09:01:15');
INSERT INTO `appointment_messages` VALUES (39, 1949, 95173, 'Prezados, boa noite!', 0, 0, '2026-03-31 21:00:14');
INSERT INTO `appointment_messages` VALUES (40, 1949, 95173, 'Infelizmente surgiu um compromisso profissional e vou precisar atender um cliente em outra cidade amanhã pela manhã e impossibilitará minha ida até o atendimento agendado. Gostaria de verificar a possibilidade de remarcação ou cancelamento do meu agendamento feito para amanhã às 08:30, para não prejudicar além do meu limite de agendamentos a agenda da colaborador responsável pelo atendimento', 0, 0, '2026-03-31 21:02:18');
INSERT INTO `appointment_messages` VALUES (41, 2001, 110817, 'já sou cadastrada , mas nunca fiz a atualização ãnual, não consigo enviar documentos pelo GERID, E dizia não existir cadastro.', 0, 0, '2026-04-01 19:58:25');
INSERT INTO `appointment_messages` VALUES (42, 2090, 95106, 'FAVOR CANCELAR A DATA', 0, 0, '2026-04-14 14:26:00');
INSERT INTO `appointment_messages` VALUES (43, 2092, 119565, 'não recebi o link da reunião.', 0, 0, '2026-04-17 09:20:24');
INSERT INTO `appointment_messages` VALUES (44, 2154, 124429, 'o atendimento é feita de forma on-line? não encontrei instruções', 0, 0, '2026-04-23 16:56:46');
INSERT INTO `appointment_messages` VALUES (45, 2163, 110557, 'bom dia', 0, 0, '2026-04-27 11:47:40');
INSERT INTO `appointment_messages` VALUES (46, 2176, 109106, 'Bom dia! Vai ser enviado um link para a reunião online?', 0, 0, '2026-04-30 07:34:13');
INSERT INTO `appointment_messages` VALUES (47, 2208, 95151, 'Bom dia, aqui é da Almeida Advocacia.', 0, 0, '2026-05-08 09:30:22');
INSERT INTO `appointment_messages` VALUES (48, 2208, 95151, 'A pedido da Dra marisa de Almeida Rauber, favor CANCELAR o atendimento dela de hoje, 08/05, às 12h, por gentileza', 0, 0, '2026-05-08 09:31:39');
INSERT INTO `appointment_messages` VALUES (49, 2224, 96711, 'Mandei os documentos pertinentes e aviso do agendamento pelo email:  joao.francielliadvocacia@gmail.com', 0, 1, '2026-05-11 15:10:52');
INSERT INTO `appointment_messages` VALUES (50, 2232, 95223, 'atendimento informações segurado, vou enviar email antes com procuraçao e documentos', 0, 1, '2026-05-12 17:52:04');
INSERT INTO `appointment_messages` VALUES (51, 2217, 95123, 'Bom dia! Infelizmente tentei cancelar o atendimento e não consegui. Não poderei comparecer em decorrência de compromisso profissional (prazo judicial).', 0, 0, '2026-05-13 09:04:47');
INSERT INTO `appointment_messages` VALUES (52, 2236, 108223, 'Oi, boa tarde. Irei receber confirmação?', 0, 0, '2026-05-13 14:35:24');
INSERT INTO `appointment_messages` VALUES (53, 2237, 96711, 'Problemas com Senha - Sebastião Aparecido Franco', 0, 0, '2026-05-13 14:39:13');
INSERT INTO `appointment_messages` VALUES (54, 2272, 142913, 'Gostaria de cancelar esse atendimento. Ele foi agendado por engano.', 0, 0, '2026-05-22 08:43:48');
INSERT INTO `appointment_messages` VALUES (55, 2279, 145715, 'Prezados, boa tarde', 0, 0, '2026-05-25 16:21:55');
INSERT INTO `appointment_messages` VALUES (56, 2279, 145715, 'tenho cadastro de acesso ao GERID mas não é possivel minha inclusao como procuradora em um processo', 0, 0, '2026-05-25 16:22:34');
INSERT INTO `appointment_messages` VALUES (57, 2279, 145715, 'nesse processo adm, atuamos uma colega e eu', 0, 0, '2026-05-25 16:22:52');
