INSERT INTO `appointments` VALUES (1493, 95109, '2025-12-15 15:00:00', '12:00:00', '12:30:00', 'Atendimento', 'Foi implantado benefício judicialmente, porém não aparece no meuinss do cliente. Ao tentar abrir novo pedido de benefício por incapacidade, informou que precisa aguardar pois tem um em aberto \"Encontrados requerimentos abertos incompatívelis no SIBE, NBs 7267037985. Para um novo requerimento, os anteriores devem ser concluídos.\"  O cliente não pode ficar sem receber. Gostaria de ver o que houve internamente para que o benefício não conste como ativo, considerando que no processo judicial o INSS informou que está implantado. ', 'no_show', NULL, NULL, '2025-12-11 17:09:58', '2026-02-26 16:24:10');
INSERT INTO `appointments` VALUES (1494, 95191, '2025-12-15 15:00:00', '10:30:00', '11:00:00', 'Atendimento', 'Aposentadoria - implemento das condições ', 'no_show', NULL, NULL, '2025-12-11 17:35:13', '2026-02-26 16:24:10');
INSERT INTO `appointments` VALUES (1495, 95195, '2025-12-17 15:00:00', '08:30:00', '09:00:00', 'Atendimento', 'INSS exigiu o seguinte:\\r\\n\\r\\n\"#### EXIGÊNCIA DO PPP\\r\\nSolicitamos cumprir a exigência em anexo referente ao PPP. Além disso, o INSS não aceita o Perfil Profissiográfico Previdenciário PPP em papel para períodos trabalhados a partir de 01/01/2023.\\r\\nPara esses casos, é obrigatório o uso do PPP Eletrônico.\\r\\nSituação atual: O Cadastro Nacional de Informações Sociais CNIS informa que não há PPP registrado para o seu vínculo, embora você tenha declarado exposição a agentes prejudiciais à saúde.\\r\\nO que você deve fazer: Entre em contato com seu empregador e solicite o envio das informações de saúde e segurança.\\r\\nDado técnico necessário: O empregador deve enviar o evento S-2240 pelo sistema eSocial.\"\\r\\n\\r\\nContudo, o trabalho a ser reconhecido foi anterior a 01/01/2023.', 'completed', NULL, NULL, '2025-12-11 20:07:31', '2026-02-26 16:24:10');
INSERT INTO `appointments` VALUES (1496, 95142, '2025-12-17 15:00:00', '09:30:00', '10:00:00', 'Atendimento', 'atendimento inss', 'completed', NULL, NULL, '2025-12-11 21:00:29', '2026-02-26 16:24:10');
