INSERT INTO `email_queue` VALUES (79, 'vitoriabaruffi@hotmail.com', NULL, 'Atualização sobre seu Formulário de Cadastramento TCMS', '\n                <h2>Olá, VITORIA RAQUEL GARCIA REGO</h2>\n                <p>Informamos que seu formulário de cadastramento foi analisado e <strong>não pôde ser aprovado</strong> neste momento.</p>\n                <p><strong>Motivo da Recusa:</strong></p>\n                <div style=\"background: #f8f9fa; padding: 15px; border-left: 4px solid #dc3545; margin: 10px 0;\">\n                  recebemos sua solicitação do sistema do INSS Digital, porém o seu Termo – TCMS veio sem os dados e assinaturas das testemunhas. Desta forma, solicito que faça novamente o cadastro pelo site com o “Termo de Compromisso de manutenção de sigilo – TCMS com o endereço completo nº, bairro, cidade, UF e CEP”, Declaração de boas práticas e o Termo de aceite do ACT”, com o nome, CPF e as assinaturas da senhora e das testemunhas.\n                </div>\n                <p>Por favor, acesse o sistema para realizar os ajustes necessários e enviar novamente.</p>\n                <br/>\n                <p>Atenciosamente,<br/>Equipe OAB/SC</p>\n              ', 'form_rejection', NULL, NULL, 'sent', '2026-04-23 19:00:44', NULL, 0, '2026-04-23 16:00:22', '2026-04-23 16:00:44');
