INSERT INTO `email_queue` VALUES (81, 'leofduarte@gmail.com', NULL, 'Atualização sobre seu Formulário de Cadastramento TCMS', '\n                <h2>Olá, LEONARDO FELIPE DUARTE</h2>\n                <p>Informamos que seu formulário de cadastramento foi analisado e <strong>não pôde ser aprovado</strong> neste momento.</p>\n                <p><strong>Motivo da Recusa:</strong></p>\n                <div style=\"background: #f8f9fa; padding: 15px; border-left: 4px solid #dc3545; margin: 10px 0;\">\n                  Fui fazer seu cadastro no INSS e deu como CPF já cadastrado isso acontece quando o Advogado já foi funcionário, estagiário do INSS ou tem cadastro do INSS na OAB de outro estado, preciso dessa informação e também fotocópia frente e verso da sua carteira da OAB e da RG para abrir um chamado para eles liberarem seu acesso.\n                </div>\n                <p>Por favor, acesse o sistema para realizar os ajustes necessários e enviar novamente.</p>\n                <br/>\n                <p>Atenciosamente,<br/>Equipe OAB/SC</p>\n              ', 'form_rejection', NULL, NULL, 'sent', '2026-04-24 17:54:18', NULL, 0, '2026-04-24 14:53:52', '2026-04-24 14:54:18');
INSERT INTO `email_queue` VALUES (82, 'mbeabernardes@gmail.com', NULL, 'Atualização sobre seu Formulário de Cadastramento TCMS', '\n                <h2>Olá, MARIA BEATRIZ MARTINS BERNARDES</h2>\n                <p>Informamos que seu formulário de cadastramento foi analisado e <strong>não pôde ser aprovado</strong> neste momento.</p>\n                <p><strong>Motivo da Recusa:</strong></p>\n                <div style=\"background: #f8f9fa; padding: 15px; border-left: 4px solid #dc3545; margin: 10px 0;\">\n                  Recebemos sua solicitação do sistema do INSS Digital, porém o seu Termo – TCMS veio sem os dados e assinaturas das testemunhas. Desta forma, solicito que faça novamente o cadastro pelo site com o “Termo de Compromisso de manutenção de sigilo – TCMS com o endereço completo nº, bairro, cidade, UF e CEP”, Declaração de boas práticas e o Termo de aceite do ACT”, com o nome, CPF e as assinaturas da senhora e das testemunhas.\n                </div>\n                <p>Por favor, acesse o sistema para realizar os ajustes necessários e enviar novamente.</p>\n                <br/>\n                <p>Atenciosamente,<br/>Equipe OAB/SC</p>\n              ', 'form_rejection', NULL, NULL, 'sent', '2026-04-24 18:09:19', NULL, 0, '2026-04-24 15:09:07', '2026-04-24 15:09:19');
